import React from 'react';
import styled from 'styled-components';
import {
  bitcoin,
  book,
  calender,
  card,
  circle,
  comment,
  dollar,
  food,
  freelance,
  medical,
  money,
  piggy,
  stocks,
  takeaway,
  trash,
  tv
} from '../../utils/icons';
import Button from '../Button/Button';
import { dateFormat } from '../../utils/dateFormat';

function IncomeItem({
  id,
  title,
  amount,
  date,
  category,
  description,
  deleteItem,
  indicatorColor,
  type
}) {
  const incomeIcon = () => {
    switch (category) {
      case 'Salario':
        return money;
      case 'Freelance':
        return freelance;
      case 'Ventas':
        return card;
      case 'Inversion':
        return stocks;
      case 'Transferencia':
        return bitcoin;
      case 'Otro':
        return piggy;
      default:
        return circle;
    }
  };

  const expenseIcon = () => {
    switch (category) {
      case 'C001':
        return food;
      case 'C002':
        return freelance;
      case 'C003':
        return tv;
      case 'C004':
        return medical;
      case 'C005':
        return book;
      case 'C006':
        return card;
      case 'C007':
        return takeaway;
      default:
        return circle;
    }
  };

  return (
    <IncomeItemStyled indicator={indicatorColor}>
      <div className="icon">
        {type === 'expense' ? expenseIcon() : incomeIcon()}
      </div>

      <div className="content">
        <h5>{title}</h5>

        <div className="inner-content">
          <div className="text">
            <p>{dollar} {amount}</p>
            <p>{calender} {dateFormat(date)}</p>
            <p>
              {comment}
              {description}
            </p>
          </div>

          <div className="btn-con">
            <Button
              icon={trash}
              bPad={'1rem'}
              bRad={'50%'}
              bg={'var(--primary-color)'}
              color={'#fff'}
              iColor={'#fff'}
              hColor={'var(--color-green)'}
              onClick={() => deleteItem(id)}
            />
          </div>
        </div>
      </div>
    </IncomeItemStyled>
  );
}

const IncomeItemStyled = styled.div`
  background: #FCF6F9;
  border: 2px solid #FFFFFF;
  box-shadow: 0px 1px 15px rgba(0, 0, 0, 0.06);
  border-radius: 20px;
  padding: 1rem;
  margin-bottom: 1rem;
  display: flex;
  align-items: center;
  gap: 1rem;
  width: 100%;
  color: #222260;

  .icon{
    width: 80px;
    height: 80px;
    border-radius: 20px;
    background: #F5F5F5;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px solid #FFFFFF;

    i{
      font-size: 2.6rem;
    }
  }

  .content{
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: .2rem;

    h5{
      font-size: 1.3rem;
      padding-left: 2rem;
      position: relative;

      &::before{
        content: '';
        position: absolute;
        left: 0;
        top: 50%;
        transform: translateY(-50%);
        width: .8rem;
        height: .8rem;
        border-radius: 50%;
        background: ${props => props.indicator};
      }
    }

    .inner-content{
      display: flex;
      justify-content: space-between;
      align-items: center;

      .text{
        display: flex;
        align-items: center;
        gap: 1.5rem;

        p{
          display: flex;
          align-items: center;
          gap: 0.5rem;
          color: var(--primary-color);
          opacity: 0.8;
        }
      }
    }
  }
`;

export default IncomeItem;
